insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И в те дни появляется <1а>Иоанн Креститель, и проповедует в <б>Иудейской <2>пустыне,',2,1,3,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И говорит: <1а>Кайтесь, ибо <2>приблизилось <3б>царство небес.',2,1,3,2);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ибо это тот, о ком было сказано через пророка Исайю, который говорит: «<а>Голос восклицающего в <1>пустыне: „<б>Приготовьте путь Господа; <2>делайте прямыми Его тропы“».',2,1,3,3);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А одежда у этого Иоанна была из <1а>верблюжьего волоса, и <б>кожаный пояс на бёдрах, а его пищей были <в>саранча и дикий мёд.',2,1,3,4);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Тогда выходил к нему <а>Иерусалим, и вся Иудея, и вся окрестность <б>Иордана,',2,1,3,5);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И <1а>крестились у него в реке <2б>Иордане, <в>исповедуя свои грехи.',2,1,3,6);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Но, увидев, что многие <1а>фарисеи и <2б>саддукеи идут к нему на <в>крещение, он сказал им: Отродье <г>гадюк! Кто подсказал вам бежать от будущего <д>гнева?',2,1,3,7);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Принесите же плод, <а>достойный вашего покаяния.',2,1,3,8);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И не вздумайте говорить внутри себя: «Отец у нас <а>Авраам», ибо говорю вам, что Бог может из этих <б>камней <1>воздвигнуть <в>детей Аврааму.',2,1,3,9);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И уже топор у корня деревьев лежит. Итак, всякое <а>дерево, не приносящее хорошего плода, срубают и бросают в <б>огонь.',2,1,3,10);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Я крещу вас в <а>воде к <б>покаянию, но <в>Тот, кто идёт за мной, сильнее меня; я недостоин понести Его <г>сандалии. Он Сам будет крестить вас в Святом <д>Духе и <1е>огне,',2,1,3,11);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И у Него в руке <а>лопата для веяния. И Он расчистит Своё гумно и <б>соберёт Свою <1>пшеницу в амбар, а мякину сожжёт неугасимым вогнём.',2,1,3,12);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Тогда приходит Иисус из <а>Галилеи на Иордан к Иоанну, чтобы <1б>креститься у него.',2,1,3,13);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Но Иоанн удерживал Его и говорил: Это мне нужно креститься у Тебя, а Ты приходишь ко мне?',2,1,3,14);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Но Иисус сказал ему в ответ: Позволь сейчас, ибо так подобает нам <а>исполнить всю <1>праведность. — Тогда он позволяет Ему.',2,1,3,15);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, <1>крестившись, Иисус сразу же вышел из воды. И вот, <а>открылись Ему <2>небеса, и Он увидел, как <3>Дух Божий сходит, словно <4б>голубь, и опускается <в>на Него.',2,1,3,16);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values (' И вот, <а>голос с небес говорит: <1>Это Мой <б>Сын, Возлюбленный, в котором Я нашёл <в>отраду.',2,1,3,17);
